1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const samePosition = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
10	  ax === bx && ay === by;
11	
12	export const nextGeneration = (cells: Cell[]): Cell[] => {
13	  const isAlive = (cell: Cell): boolean =>
14	    cells.some((live) => samePosition(live, cell));
15	
16	  const countLiveNeighbors = ([x, y]: Cell): number =>
17	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive([x + dx, y + dy])).length;
18	
19	  const survives = (cell: Cell): boolean => {
20	    const neighborCount = countLiveNeighbors(cell);
21	    return neighborCount === 2 || neighborCount === 3;
22	  };
23	
24	  return cells.filter(survives);
25	};
